import{_ as a,c as t,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Solución de Invalid Grant: Recuperación de Cuenta Deshabilitada | Antigravity-Manager","description":"Aprende el significado del error invalid_grant y la lógica de procesamiento automático. Después de confirmar que refresh_token ha expirado, activa la reactivación automática volviendo a agregar la cuenta mediante OAuth, y verifica que la recuperación surta efecto en Proxy.","frontmatter":{"title":"Solución de Invalid Grant: Recuperación de Cuenta Deshabilitada | Antigravity-Manager","sidebarTitle":"Cómo recuperar una cuenta deshabilitada","subtitle":"invalid_grant y deshabilitación automática de cuenta: por qué ocurre y cómo recuperarla","description":"Aprende el significado del error invalid_grant y la lógica de procesamiento automático. Después de confirmar que refresh_token ha expirado, activa la reactivación automática volviendo a agregar la cuenta mediante OAuth, y verifica que la recuperación surta efecto en Proxy.","tags":["FAQ","solución de problemas","OAuth","gestión de cuentas","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"es/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),i={name:"es/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function n(s,e,l,d,c,u){return o(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="invalid-grant-y-deshabilitacion-automatica-de-cuenta-por-que-ocurre-y-como-recuperarla" tabindex="-1">invalid_grant y Deshabilitación Automática de Cuenta: Por Qué Ocurre y Cómo Recuperarla <a class="header-anchor" href="#invalid-grant-y-deshabilitacion-automatica-de-cuenta-por-que-ocurre-y-como-recuperarla" aria-label="Permalink to &quot;invalid_grant y Deshabilitación Automática de Cuenta: Por Qué Ocurre y Cómo Recuperarla&quot;">​</a></h1><h2 id="lo-que-podras-hacer-despues-de-esta-leccion" tabindex="-1">Lo Que Podrás Hacer Después de Esta Lección <a class="header-anchor" href="#lo-que-podras-hacer-despues-de-esta-leccion" aria-label="Permalink to &quot;Lo Que Podrás Hacer Después de Esta Lección&quot;">​</a></h2><ul><li>Cuando veas <code>invalid_grant</code>, sabrás qué tipo de problema de refresh_token corresponde</li><li>Entender claramente &quot;por qué la cuenta de repente no está disponible&quot;: en qué situaciones se deshabilita automáticamente y cómo maneja esto el sistema</li><li>Recuperar la cuenta por el camino más corto y confirmar que la recuperación ya está surtiendo efecto en el Proxy que se está ejecutando</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu Situación Actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu Situación Actual&quot;">​</a></h2><ul><li>Al llamar al Proxy local, falla repentinamente y aparece <code>invalid_grant</code> en el mensaje de error</li><li>La cuenta todavía está en la lista Accounts, pero el Proxy siempre la omite (o sientes que &quot;ya nunca se usa&quot;)</li><li>Cuando tienes pocas cuentas, después de encontrar <code>invalid_grant</code> una vez, la disponibilidad general disminuye claramente</li></ul><h2 id="que-es-invalid-grant" tabindex="-1">Qué Es invalid_grant <a class="header-anchor" href="#que-es-invalid-grant" aria-label="Permalink to &quot;Qué Es invalid_grant&quot;">​</a></h2><p><strong>invalid_grant</strong> es un tipo de error que Google OAuth devuelve al actualizar <code>access_token</code>. Para Antigravity Tools, significa que el <code>refresh_token</code> de alguna cuenta probablemente ha sido revocado o expirado, y continuar reintentando solo causará fallas repetidas, por lo que el sistema marcará esa cuenta como no disponible y la eliminará del pool de proxies.</p><h2 id="idea-central-el-sistema-no-omite-temporalmente-sino-que-deshabilita-permanentemente" tabindex="-1">Idea Central: El Sistema No Omite Temporalmente, Sino Que Deshabilita Permanentemente <a class="header-anchor" href="#idea-central-el-sistema-no-omite-temporalmente-sino-que-deshabilita-permanentemente" aria-label="Permalink to &quot;Idea Central: El Sistema No Omite Temporalmente, Sino Que Deshabilita Permanentemente&quot;">​</a></h2><p>Cuando el Proxy detecta que la cadena de error de actualización de token contiene <code>invalid_grant</code>, hace dos cosas:</p><ol><li><strong>Escribe la cuenta como disabled</strong> (persiste en el JSON de la cuenta)</li><li><strong>Elimina la cuenta del token pool en memoria</strong> (evita seleccionar repetidamente la misma cuenta defectuosa)</li></ol><p>Esta es la razón por la que ves &quot;la cuenta sigue ahí, pero el Proxy ya no la usa&quot;.</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>: La cuenta está &quot;completamente deshabilitada&quot; (la razón típica es <code>invalid_grant</code>). Se omite directamente al cargar el pool de cuentas.</li><li><code>proxy_disabled=true</code>: La cuenta simplemente &quot;no está disponible para Proxy&quot; (deshabilitación manual/operación por lotes/lógica relacionada con protección de cuota), con una semántica diferente.</li></ul><p>Estos dos estados se juzgan por separado al cargar el pool de cuentas: primero se juzga <code>disabled</code>, luego se hace el juicio de protección de cuota y <code>proxy_disabled</code>.</p></div><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-confirmar-si-el-invalid-grant-fue-disparado-por-actualizacion-de-refresh-token" tabindex="-1">Paso 1: Confirmar Si El invalid_grant Fue Disparado Por Actualización de refresh_token <a class="header-anchor" href="#paso-1-confirmar-si-el-invalid-grant-fue-disparado-por-actualizacion-de-refresh-token" aria-label="Permalink to &quot;Paso 1: Confirmar Si El invalid_grant Fue Disparado Por Actualización de refresh_token&quot;">​</a></h3><p><strong>Por qué</strong>: <code>invalid_grant</code> puede aparecer en múltiples cadenas de llamadas, pero la &quot;deshabilitación automática&quot; de este proyecto solo se dispara cuando <strong>falla la actualización de access_token</strong>.</p><p>En los registros del Proxy, verás registros de error similares (las palabras clave son <code>Token 刷新失败</code> + <code>invalid_grant</code>):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 刷新失败 (&lt;email&gt;): &lt;...invalid_grant...&gt;，尝试下一个账号</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>: Después de que una misma cuenta aparezca <code>invalid_grant</code>, muy pronto ya no será seleccionada (porque fue eliminada del token pool).</p><h3 id="paso-2-verificar-el-campo-disabled-en-el-archivo-de-cuenta-opcional-pero-mas-preciso" tabindex="-1">Paso 2: Verificar El Campo disabled En El Archivo de Cuenta (Opcional, Pero Más Preciso) <a class="header-anchor" href="#paso-2-verificar-el-campo-disabled-en-el-archivo-de-cuenta-opcional-pero-mas-preciso" aria-label="Permalink to &quot;Paso 2: Verificar El Campo disabled En El Archivo de Cuenta (Opcional, Pero Más Preciso)&quot;">​</a></h3><p><strong>Por qué</strong>: La deshabilitación automática es &quot;persistente en disco&quot;, y después de confirmar el contenido del archivo, puedes descartar el juicio erróneo de &quot;solo es rotación temporal&quot;.</p><p>El archivo de cuenta se encuentra en el directorio <code>accounts/</code> del directorio de datos de la aplicación (la ubicación del directorio de datos se encuentra en <strong><a href="./../../start/first-run-data/">Primera Inicio: Directorio de Datos, Registros, Bandeja y Inicio Automático</a></strong>). Cuando la cuenta está deshabilitada, el archivo mostrará estos tres campos:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>: <code>disabled</code> es <code>true</code>, y <code>disabled_reason</code> contiene el prefijo <code>invalid_grant:</code>.</p><h3 id="paso-3-recuperar-la-cuenta-metodo-recomendado-volver-a-agregar-la-misma-cuenta" tabindex="-1">Paso 3: Recuperar La Cuenta (Método Recomendado: Volver a Agregar La Misma Cuenta) <a class="header-anchor" href="#paso-3-recuperar-la-cuenta-metodo-recomendado-volver-a-agregar-la-misma-cuenta" aria-label="Permalink to &quot;Paso 3: Recuperar La Cuenta (Método Recomendado: Volver a Agregar La Misma Cuenta)&quot;">​</a></h3><p><strong>Por qué</strong>: La &quot;recuperación&quot; de este proyecto no es hacer clic en un interruptor manualmente en el Proxy, sino activar la reactivación automática mediante &quot;actualización explícita de token&quot;.</p><p>Ve a la página <strong>Accounts</strong>, vuelve a agregar la cuenta con tus nuevas credenciales (elige cualquiera de las dos formas):</p><ol><li>Vuelve a realizar el proceso de autorización OAuth (ver <strong><a href="./../../start/add-account/">Agregar Cuenta: Canales Doble OAuth/Refresh Token y Mejores Prácticas</a></strong>)</li><li>Vuelve a agregar con un nuevo <code>refresh_token</code> (el sistema usará el correo devuelto por Google como estándar para hacer upsert)</li></ol><p>Cuando el sistema detecta que el <code>refresh_token</code> o <code>access_token</code> que upsertaste esta vez es diferente del valor anterior, y la cuenta estaba previamente en <code>disabled=true</code>, automáticamente borrará:</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>Lo que deberías ver</strong>: La cuenta ya no está en estado disabled, y (si el Proxy se está ejecutando) el pool de cuentas se recargará automáticamente, haciendo que la recuperación surta efecto inmediatamente.</p><h3 id="paso-4-verificar-si-la-recuperacion-ya-esta-surtiendo-efecto-en-el-proxy" tabindex="-1">Paso 4: Verificar Si La Recuperación Ya Está Surtiendo Efecto En El Proxy <a class="header-anchor" href="#paso-4-verificar-si-la-recuperacion-ya-esta-surtiendo-efecto-en-el-proxy" aria-label="Permalink to &quot;Paso 4: Verificar Si La Recuperación Ya Está Surtiendo Efecto En El Proxy&quot;">​</a></h3><p><strong>Por qué</strong>: Si solo tienes una cuenta, u otras cuentas tampoco están disponibles, después de la recuperación deberías ver inmediatamente &quot;la disponibilidad ha vuelto&quot;.</p><p>Método de verificación:</p><ol><li>Inicia una solicitud que active la actualización de token (por ejemplo, espera a que el token esté cerca de expirar y luego solicita)</li><li>Observa que los registros ya no muestran el mensaje de &quot;omitir cuenta disabled&quot;</li></ol><p><strong>Lo que deberías ver</strong>: La solicitud pasa normalmente, y los registros ya no muestran el flujo de deshabilitación <code>invalid_grant</code> para esa cuenta.</p><h2 id="advertencias-sobre-problemas-comunes" tabindex="-1">Advertencias Sobre Problemas Comunes <a class="header-anchor" href="#advertencias-sobre-problemas-comunes" aria-label="Permalink to &quot;Advertencias Sobre Problemas Comunes&quot;">​</a></h2><h3 id="❌-tratar-disabled-como-rotacion-temporal" tabindex="-1">❌ Tratar disabled Como &quot;Rotación Temporal&quot; <a class="header-anchor" href="#❌-tratar-disabled-como-rotacion-temporal" aria-label="Permalink to &quot;❌ Tratar disabled Como &quot;Rotación Temporal&quot;&quot;">​</a></h3><p>Si solo miras &quot;la cuenta todavía está ahí&quot; en la UI, es fácil juzgar erróneamente que &quot;el sistema simplemente no la está usando temporalmente&quot;. Pero <code>disabled=true</code> se escribe en el disco, y continuará surtiendo efecto incluso después de reiniciar.</p><h3 id="❌-solo-complementar-access-token-no-actualizar-refresh-token" tabindex="-1">❌ Solo Complementar access_token, No Actualizar refresh_token <a class="header-anchor" href="#❌-solo-complementar-access-token-no-actualizar-refresh-token" aria-label="Permalink to &quot;❌ Solo Complementar access_token, No Actualizar refresh_token&quot;">​</a></h3><p>El punto de disparo de <code>invalid_grant</code> es el <code>refresh_token</code> utilizado al actualizar <code>access_token</code>. Si solo obtienes temporalmente un <code>access_token</code> que todavía funciona, pero <code>refresh_token</code> sigue inválido, luego se disparará nuevamente la deshabilitación.</p><h2 id="puntos-de-control-✅" tabindex="-1">Puntos de Control ✅ <a class="header-anchor" href="#puntos-de-control-✅" aria-label="Permalink to &quot;Puntos de Control ✅&quot;">​</a></h2><ul><li>[ ] Puedes confirmar en los registros que <code>invalid_grant</code> proviene de la falla de actualización de refresh_token</li><li>[ ] Conoces la diferencia semántica entre <code>disabled</code> y <code>proxy_disabled</code></li><li>[ ] Puedes recuperar la cuenta volviendo a agregarla (OAuth o refresh_token)</li><li>[ ] Puedes verificar que la recuperación ya está surtiendo efecto en el Proxy que se está ejecutando</li></ul><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de Esta Lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de Esta Lección&quot;">​</a></h2><ul><li>Cuando se dispara <code>invalid_grant</code>, el Proxy <strong>persistirá la cuenta como disabled</strong> y la eliminará del token pool, evitando fallas repetidas</li><li>La clave para la recuperación es &quot;actualización explícita de token&quot; (volver a OAuth o volver a agregar con un nuevo refresh_token), el sistema borrará automáticamente los campos <code>disabled_*</code></li><li>El JSON de cuenta en el directorio de datos es la fuente de estado más autorizada (deshabilitación/razón/tiempo están todos ahí)</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima Lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima Lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../auth-401/">401/Fallo de Autenticación: auth_mode, Compatibilidad de Header y Lista de Verificación de Configuración del Cliente</a></strong>.</p><p>Aprenderás:</p><ul><li>401 generalmente es qué capa no coincide entre &quot;modo/Key/Header&quot;</li><li>Qué header de autenticación deben llevar diferentes clientes</li><li>Cómo hacer autoverificación y reparación por el camino más corto</li></ul></blockquote><hr><h2 id="apendice-referencias-de-codigo-fuente" tabindex="-1">Apéndice: Referencias de Código Fuente <a class="header-anchor" href="#apendice-referencias-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencias de Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir ubicaciones de código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del Archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Explicación de diseño: problema de invalid_grant y comportamiento de cambios</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>Omitir <code>disabled=true</code> al cargar el pool de cuentas</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>Identificar <code>invalid_grant</code> al fallar la actualización de token y deshabilitar la cuenta</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td>Persistir escritura de <code>disabled/disabled_at/disabled_reason</code> y eliminar de memoria</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td>Truncamiento de <code>disabled_reason</code> (evitar inflación del archivo de cuenta)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>Limpiar automáticamente <code>disabled_*</code> en upsert (cambio de token se considera que el usuario ya reparó las credenciales)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>Recargar automáticamente las cuentas del proxy después de volver a agregar la cuenta (surte efecto inmediatamente mientras se ejecuta)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const h=a(i,[["render",n]]);export{m as __pageData,h as default};
